function n(e){let r=[...e];for(let t=r.length-1;t>0;t-=1){let o=Math.floor(Math.random()*(t+1));[r[t],r[o]]=[r[o],r[t]]}return r}function a(e,r=6){if(!Number.isFinite(e))return"Impossible";let t=Number(e.toFixed(r));return new Intl.NumberFormat("fr-FR",{maximumFractionDigits:r}).format(t)}function m(e){return`${(Math.max(0,Number(e)||0)/1e3).toFixed(1)}s`}function i(e){return String(e||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().replace(/[^a-z0-9]/g,"")}export{n as a,a as b,m as c,i as d};
